-- d740.lua - Luraph VM full dispatcher trace
-- Traces ALL 5 VM dispatchers: MAIN, VA, VB, VC, VD
-- Use in Delta executor. Output saved to 8je.txt

local _out = {}
local _oprint = print
local function _print(...)
  local t = {}
  for i = 1, select("#", ...) do t[i] = tostring(select(i, ...)) end
  _out[#_out + 1] = table.concat(t, "\t")
  _oprint(table.concat(t, "\t"))
end
print = _print

local _b64c = "ABCDEFGHIJKLMNOPQRSTUVWXYZabcdefghijklmnopqrstuvwxyz0123456789+/"
local _b64i = {}
for i = 1, #_b64c do _b64i[_b64c:sub(i, i)] = i - 1 end
local function b64dec(s)
  s = s:gsub("[=%s]", "")
  local out = {}
  for i = 1, #s, 4 do
    local rem = math.min(#s - i + 1, 4)
    if rem < 2 then break end
    local c1 = _b64i[s:sub(i, i)] or 0
    local c2 = rem >= 2 and (_b64i[s:sub(i+1, i+1)] or 0) or 0
    local c3 = rem >= 3 and (_b64i[s:sub(i+2, i+2)] or 0) or 0
    local c4 = rem >= 4 and (_b64i[s:sub(i+3, i+3)] or 0) or 0
    local n = c1 * 262144 + c2 * 4096 + c3 * 64 + c4
    out[#out + 1] = string.char(math.floor(n / 65536) % 256)
    if rem >= 3 then out[#out + 1] = string.char(math.floor(n / 256) % 256) end
    if rem >= 4 then out[#out + 1] = string.char(n % 256) end
  end
  return table.concat(out, "")
end

