local bytecode = b64dec(BYTECODE_B64)
local vm_src = VM_SRC
print("[*] VM=" .. #vm_src .. " BC=" .. #bytecode)
print("[*] Patched vm_src has 5 trace injection points")
print("[*] Running...")

local fn, ferr = loadstring(vm_src, "inner_vm")
if not fn then
  print("[!] loadstring failed: " .. tostring(ferr))
  return
end

local buf = buffer.fromstring(bytecode)
local ok, err = pcall(fn, buf)
print(string.format("[*] result: ok=%s err=%s", tostring(ok), tostring(err):sub(1, 200)))
print(string.format("[*] trace entries: %d", #_out))

if writefile then
  pcall(writefile, "8je.txt", table.concat(_out, "\n"))
  print("[*] Saved (" .. #_out .. " lines) -> 8je.txt")
elseif getgenv and getgenv().writefile then
  pcall(getgenv().writefile, "8je.txt", table.concat(_out, "\n"))
  print("[*] Saved (" .. #_out .. " lines) -> 8je.txt")
else
  print("[*] No writefile - copy from console")
end
print("=== D740 DONE ===")

-- Final flush for A
do
  local _f = readfile("8je.txt") or ""
  if __out ~= nil and __outN > 0 then
    writefile("8je.txt", _f .. table.concat(__out, "\n") .. "\n")
    __written = __written + __outN
  end
end
print("[*] A traced:", __tcA or 0, "written:", __written or 0)
print("[*] M count:", __tcM or 0)
print("[*] M V log:")
if __vlog then
  for _i = 1, math.min(#__vlog, 60) do
    print("  " .. (__vlog[_i] or "?"))
  end
end
-- Count V==113 occurrences by scanning binary log? No. Add separate counter:
print("[*] V==113 count:", __v113count or 0)
print("[*] B count:", __tcB or 0)
print("[*] C count:", __tcC or 0)
print("[*] D count:", __tcD or 0)
for _g = 0, 13 do
  print("[*] g=" .. _g, "count:", __gcount[_g] or 0)
end
